#include <iostream>
#include <pthread.h>
#include <semaphore.h>

sem_t sem;

void* worker(void* arg) {
    sem_wait(&sem);   // wait (P)
    std::cout << "Thread " << pthread_self() << " entered critical section\n";
    sem_post(&sem);   // signal (V)
    return nullptr;
}

int main() {
    pthread_t t1, t2;
    sem_init(&sem, 0, 1); // binary semaphore (mutex-like)

    pthread_create(&t1, nullptr, worker, nullptr);
    pthread_create(&t2, nullptr, worker, nullptr);

    pthread_join(t1, nullptr);
    pthread_join(t2, nullptr);

    sem_destroy(&sem);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    FILE *src, *dest;
    char buffer[256];

    // Open source file for reading
    src = fopen("input.txt", "r");
    if (src == NULL) { // Always check for NULL!
        perror("Error opening input file");
        return EXIT_FAILURE;
    }

    // Open destination file for writing
    dest = fopen("output.txt", "w");
    if (dest == NULL) { // Always check for NULL!
        perror("Error opening output file");
        fclose(src);
        return EXIT_FAILURE;
    }

    // Copy line by line
    while (fgets(buffer, sizeof(buffer), src) != NULL) {
        fputs(buffer, dest);
    }

    // Check for errors
    if (ferror(src)) {
        fprintf(stderr, "Error reading input file\n");
    }
    if (ferror(dest)) {
        fprintf(stderr, "Error writing output file\n");
    }

    // Close files
    fclose(src);
    fclose(dest);

    printf("File copy completed successfully.\n");
    return EXIT_SUCCESS;
}

#include <fcntl.h>   // for open, creat
#include <unistd.h>  // for write, close
#include <stdio.h>   // for perror
#include <string.h>  // for strlen

int main(void) {
    int fd;
    const char *msg = "Hello, low-level I/O!\n";

    // Create or open file with write-only access
    fd = open("lowlevel.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) {
        perror("open");
        return 1;
    }

    // Write to file
    if (write(fd, msg, strlen(msg)) == -1) {
        perror("write");
        close(fd);
        return 1;
    }

    // Close file
    if (close(fd) == -1) {
        perror("close");
        return 1;
    }

    return 0;
}

#include <iostream>
#include <unistd.h>   // for fork(), getpid()
#include <sys/wait.h> // for wait()

int main() {
    pid_t pid = fork();  // Create a new process

    if (pid < 0) {
        std::cerr << "Fork failed!" << std::endl;
        return 1;
    }
    else if (pid == 0) { // Child process
        std::cout << "Hello from child! PID = " << getpid() << std::endl;
    }
    else { // Parent process
        std::cout << "Hello from parent! PID = " << getpid()
                  << ", child PID = " << pid << std::endl;
        wait(nullptr); // Wait for child to finish
    }

    return 0;
}

#include <iostream>
#include <unistd.h>   // fork, exec, exit
#include <sys/wait.h> // wait

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        std::cerr << "Fork failed!" << std::endl;
        return 1;
    }
    else if (pid == 0) {
        // Child process: replace with "ls" program
        execlp("ls", "ls", "-l", nullptr);
        // If exec fails:
        std::cerr << "Exec failed!" << std::endl;
        exit(1);
    }
    else {
        // Parent process: wait for child
        int status;
        wait(&status);
        std::cout << "Child finished with status " << status << std::endl;
    }

    return 0;
}

