#include <iostream>
#include <csignal>
#include <unistd.h>

void handler(int sig) {
    std::cout << "Caught signal " << sig << std::endl;
}

int main() {
    // Install handler for SIGUSR1
    signal(SIGUSR1, handler);

    pid_t pid = fork();

    if (pid == 0) {
        // Child process: wait for signal
        pause(); // wait until a signal arrives
        std::cout << "Child exiting\n";
        _exit(0);
    } else {
        // Parent process: send signal to child
        sleep(1);
        kill(pid, SIGUSR1); // send SIGUSR1
        wait(nullptr);
        std::cout << "Parent done\n";
    }

    return 0;
}

#include <iostream>
#include <pthread.h>
#include <vector>

struct ThreadData {
    int start;
    int end;
    const std::vector<int>* arr;
    long long partial_sum;
};

// Worker function for each thread
void* compute_partial_sum(void* arg) {
    ThreadData* data = (ThreadData*)arg;
    data->partial_sum = 0;
    for (int i = data->start; i < data->end; ++i) {
        data->partial_sum += (*(data->arr))[i];
    }
    return nullptr;
}

int main() {
    const int N = 1000000;   // size of array
    const int NUM_THREADS = 4;
    std::vector<int> arr(N, 1); // array filled with 1s

    pthread_t threads[NUM_THREADS];
    ThreadData thread_data[NUM_THREADS];

    int chunk_size = N / NUM_THREADS;

    // Fork: create threads
    for (int i = 0; i < NUM_THREADS; ++i) {
        thread_data[i].start = i * chunk_size;
        thread_data[i].end = (i == NUM_THREADS - 1) ? N : (i + 1) * chunk_size;
        thread_data[i].arr = &arr;
        pthread_create(&threads[i], nullptr, compute_partial_sum, &thread_data[i]);
    }

    // Join: wait for threads and combine results
    long long total_sum = 0;
    for (int i = 0; i < NUM_THREADS; ++i) {
        pthread_join(threads[i], nullptr);
        total_sum += thread_data[i].partial_sum;
    }

    std::cout << "Total sum = " << total_sum << std::endl;
    return 0;
}

